import{f as n,o as a,c as e,a2 as p}from"./chunks/framework.DHYrF-q6.js";const u=JSON.parse('{"title":"一致性协议","description":"","frontmatter":{"title":"一致性协议","outline":[2,3]},"headers":[],"relativePath":"middleware/distributed-system/consensus.md","filePath":"middleware/distributed-system/consensus.md","lastUpdated":1780747276000}'),t={name:"middleware/distributed-system/consensus.md"};function l(r,s,i,o,d,c){return a(),e("div",null,[...s[0]||(s[0]=[p(`<h1 id="一致性协议" tabindex="-1">一致性协议 <a class="header-anchor" href="#一致性协议" aria-label="Permalink to &quot;一致性协议&quot;">​</a></h1><blockquote><p>共识（Consensus）是分布式系统最核心的问题：<strong>一组节点如何就某个共同的值或决策达成一致</strong>，即使部分节点可能出现故障。</p></blockquote><h2 id="paxos-算法" tabindex="-1">Paxos 算法 <a class="header-anchor" href="#paxos-算法" aria-label="Permalink to &quot;Paxos 算法&quot;">​</a></h2><p>Paxos 由 Leslie Lamport 于 1990 年提出，是共识算法领域的奠基之作。由于其正确性证明和工程实现的复杂度，Lamport 在 2001 年发表了简化的描述性论文 <em>Paxos Made Simple</em>。</p><h3 id="basic-paxos-三角色模型" tabindex="-1">Basic Paxos 三角色模型 <a class="header-anchor" href="#basic-paxos-三角色模型" aria-label="Permalink to &quot;Basic Paxos 三角色模型&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>         ┌──────────┐</span></span>
<span class="line"><span>         │ Proposer │ 提案者：发起提案（proposal），推动共识过程</span></span>
<span class="line"><span>         └────┬─────┘</span></span>
<span class="line"><span>              │</span></span>
<span class="line"><span>    ┌─────────┼─────────┐</span></span>
<span class="line"><span>    │         │         │</span></span>
<span class="line"><span>    ▼         ▼         ▼</span></span>
<span class="line"><span>┌───────┐ ┌───────┐ ┌─────────┐</span></span>
<span class="line"><span>│Acceptor│ │Acceptor│ │Acceptor │ 接受者：对提案进行投票表决</span></span>
<span class="line"><span>└───────┘ └───────┘ └─────────┘</span></span>
<span class="line"><span>    ▲         ▲         ▲</span></span>
<span class="line"><span>    │         │         │</span></span>
<span class="line"><span>    └─────────┼─────────┘</span></span>
<span class="line"><span>              │</span></span>
<span class="line"><span>         ┌────┴─────┐</span></span>
<span class="line"><span>         │ Learner  │ 学习者：学习最终被选定的值</span></span>
<span class="line"><span>         └──────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>一个物理节点通常同时扮演多个角色。</p><h3 id="两阶段流程" tabindex="-1">两阶段流程 <a class="header-anchor" href="#两阶段流程" aria-label="Permalink to &quot;两阶段流程&quot;">​</a></h3><p><strong>阶段一：Prepare（准备阶段）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proposer                                Acceptors</span></span>
<span class="line"><span>   │                                        │</span></span>
<span class="line"><span>   │ ─── Prepare(n) ────────────────────►   │  n = 提案编号（全局唯一且递增）</span></span>
<span class="line"><span>   │                                        │</span></span>
<span class="line"><span>   │ ◄── Promise(n&#39;, v&#39;) ───────────────    │  返回：已接受的最高编号 n&#39; 及对应值 v&#39;</span></span>
<span class="line"><span>   │                                        │  同时承诺：不再接受编号 &lt; n 的提案</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><ol><li>Proposer 选择一个全局唯一且递增的提案编号 n，向 <strong>多数派</strong> Acceptors 发送 Prepare(n) 请求。</li><li>Acceptor 收到 Prepare(n) 后： <ul><li>如果 n 大于它见过的<strong>最大编号</strong>，则承诺不再接受任何编号小于 n 的提案，并返回已经 Accepted 的最大编号的值（如果有的话）。</li><li>否则拒绝。</li></ul></li></ol><p><strong>阶段二：Accept（接受阶段）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proposer                                Acceptors</span></span>
<span class="line"><span>   │                                        │</span></span>
<span class="line"><span>   │ ─── Accept(n, v) ─────────────────►    │</span></span>
<span class="line"><span>   │                                        │</span></span>
<span class="line"><span>   │ ◄── Accepted(n, v) ────────────────    │</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ol><li>Proposer 收到<strong>多数派</strong> Promises 后： <ul><li>如果所有 Promise 中都没有附带已接受的值，Proposer 可以自由选择值 v；</li><li>否则，必须选择具有<strong>最高编号</strong>的那个值作为 v（保证安全性的关键）。</li></ul></li><li>向多数派 Acceptors 发送 Accept(n, v)。</li><li>Acceptor 收到 Accept(n, v) 后：如果 n 不小于它承诺过的最小编号，则接受该值。</li><li>一旦多数派接受，该值被确定（Chosen）。</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Basic Paxos 完整流程示意：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Time ──────────────────────────────────────────────────────────►</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Proposer:     ─── Prepare(5) ────►      ─── Accept(5, &quot;X&quot;) ────►</span></span>
<span class="line"><span>                    │                              │</span></span>
<span class="line"><span>Acceptor1:    ◄── Promise(ok)      ◄── Accepted(ok)</span></span>
<span class="line"><span>Acceptor2:    ◄── Promise(ok)      ◄── Accepted(ok)</span></span>
<span class="line"><span>Acceptor3:    ◄── Promise(ok)      ◄── Accepted(ok)</span></span>
<span class="line"><span>                    │                              │</span></span>
<span class="line"><span>              多数派 Promise              多数派 Accept → 值 &quot;X&quot; 确定</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h3 id="multi-paxos-优化" tabindex="-1">Multi-Paxos 优化 <a class="header-anchor" href="#multi-paxos-优化" aria-label="Permalink to &quot;Multi-Paxos 优化&quot;">​</a></h3><p>Basic Paxos 每确定一个值需要两轮 RPC，效率低。Multi-Paxos 的核心优化：</p><ol><li><strong>选举一个稳定的 Leader</strong>：Leader 兼任唯一的 Proposer，避免多 Proposer 之间的 Prepare 冲突（活锁问题）；</li><li><strong>跳过 Prepare 阶段</strong>：Leader 任期内的第一个提案仍需两阶段，后续提案直接进入 Accept 阶段（只需一轮 RPC）；</li><li><strong>流水线化</strong>：可以同时推进多个实例（instance），每个 instance 确定日志中的一个位置。</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Multi-Paxos 简化后的流程：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Leader 选举成功后：</span></span>
<span class="line"><span>Instance 1:  Prepare(1.1) → Accept(1.1, v1)</span></span>
<span class="line"><span>Instance 2:  Accept(1.2, v2)    ← 跳过 Prepare！</span></span>
<span class="line"><span>Instance 3:  Accept(1.3, v3)    ← 跳过 Prepare！</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>Instance N:  Accept(1.N, vN)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="工程难点" tabindex="-1">工程难点 <a class="header-anchor" href="#工程难点" aria-label="Permalink to &quot;工程难点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>难点</th><th>说明</th></tr></thead><tbody><tr><td><strong>活锁 (Livelock)</strong></td><td>多个 Proposer 同时发起 Prepare，互相抢占导致无限循环。解决：随机退避 + Leader 选举。</td></tr><tr><td><strong>日志空洞</strong></td><td>Multi-Paxos 中可能有些 instance 未确定（no-op 填充或等待）。</td></tr><tr><td><strong>成员变更</strong></td><td>如何安全地变更集群节点列表。解决：联合共识（Joint Consensus）。</td></tr><tr><td><strong>实现复杂度</strong></td><td>Lamport 的论文只给出了算法的核心，工程化细节（磁盘持久化、快照、日志压缩）需自行填补。</td></tr></tbody></table><hr><h2 id="raft-算法" tabindex="-1">Raft 算法 <a class="header-anchor" href="#raft-算法" aria-label="Permalink to &quot;Raft 算法&quot;">​</a></h2><p>Raft 由 Diego Ongaro 和 John Ousterhout 于 2014 年提出，设计目标就是<strong>可理解性</strong>（Understandability）。它将共识问题分解为三个相对独立的子问题。</p><h3 id="子问题一-leader-election-领导者选举" tabindex="-1">子问题一：Leader Election（领导者选举） <a class="header-anchor" href="#子问题一-leader-election-领导者选举" aria-label="Permalink to &quot;子问题一：Leader Election（领导者选举）&quot;">​</a></h3><p>每个节点处于三种角色之一：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        启动时</span></span>
<span class="line"><span>          │</span></span>
<span class="line"><span>          ▼</span></span>
<span class="line"><span>    ┌──────────┐   超时，开始选举     ┌──────────┐</span></span>
<span class="line"><span>    │ Follower │ ───────────────────► │Candidate │</span></span>
<span class="line"><span>    └──────────┘                      └──────────┘</span></span>
<span class="line"><span>          ▲                                │</span></span>
<span class="line"><span>          │   发现更高 Term 的 Leader        │ 赢得多数票</span></span>
<span class="line"><span>          │                                ▼</span></span>
<span class="line"><span>          │                         ┌──────────┐</span></span>
<span class="line"><span>          └─────────────────────────│  Leader  │</span></span>
<span class="line"><span>                发现更高 Term        └──────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>Term（任期）是 Raft 中的逻辑时钟，全局单调递增。每次选举 Term + 1。</p><p>选举流程（RequestVote RPC）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>              ┌──────────────────────────────────────────┐</span></span>
<span class="line"><span>              │  Follower 的 election timeout 触发        │</span></span>
<span class="line"><span>              │            ↓                              │</span></span>
<span class="line"><span>              │  term++, 转为 Candidate, 给自己投票        │</span></span>
<span class="line"><span>              │            ↓                              │</span></span>
<span class="line"><span>              │  向所有节点发送 RequestVote RPC            │</span></span>
<span class="line"><span>              │            ↓                              │</span></span>
<span class="line"><span>              │  ┌─────────────────────────────┐          │</span></span>
<span class="line"><span>              │  │  收到多数票 → 成为 Leader      │          │</span></span>
<span class="line"><span>              │  │  收到更高 term → 退回 Follower  │          │</span></span>
<span class="line"><span>              │  │  超时无结果 → term++, 重选     │          │</span></span>
<span class="line"><span>              │  └─────────────────────────────┘          │</span></span>
<span class="line"><span>              └──────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>随机选举超时（150-300ms）是避免分裂投票（Split Vote）的关键机制。</p><h3 id="子问题二-log-replication-日志复制" tabindex="-1">子问题二：Log Replication（日志复制） <a class="header-anchor" href="#子问题二-log-replication-日志复制" aria-label="Permalink to &quot;子问题二：Log Replication（日志复制）&quot;">​</a></h3><p>Leader 接收客户端请求，将日志条目复制到所有 Follower：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client                    Leader                    Followers</span></span>
<span class="line"><span>  │                         │                          │</span></span>
<span class="line"><span>  │ ── SET x=5 ────────►    │                          │</span></span>
<span class="line"><span>  │                         │ 将 {term:3, cmd:&quot;x=5&quot;}   │</span></span>
<span class="line"><span>  │                         │ 追加到本地日志             │</span></span>
<span class="line"><span>  │                         │                          │</span></span>
<span class="line"><span>  │                         │ ── AppendEntries ──────►  │</span></span>
<span class="line"><span>  │                         │    (prevLogIndex=2,       │</span></span>
<span class="line"><span>  │                         │     prevLogTerm=2,        │</span></span>
<span class="line"><span>  │                         │     entries=[{3,&quot;x=5&quot;}],  │</span></span>
<span class="line"><span>  │                         │     leaderCommit=0)       │</span></span>
<span class="line"><span>  │                         │                          │</span></span>
<span class="line"><span>  │                         │ ◄── 成功响应 ───────────   │</span></span>
<span class="line"><span>  │                         │                          │</span></span>
<span class="line"><span>  │                         │ 收到多数派响应后：          │</span></span>
<span class="line"><span>  │                         │ commitIndex 推进           │</span></span>
<span class="line"><span>  │ ◄── 确认 ────────────── │                          │</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>Leader 的 commitIndex 推进后，下一次 AppendEntries 会携带 leaderCommit，通知 Follower 可以提交。</p><p><strong>日志一致性检查</strong>：AppendEntries RPC 包含 <code>prevLogIndex</code> 和 <code>prevLogTerm</code>，Follower 检查自己在该位置的日志是否匹配。不匹配则拒绝，Leader 回退 <code>nextIndex</code> 重试，直到找到匹配点。</p><h3 id="子问题三-safety-安全性" tabindex="-1">子问题三：Safety（安全性） <a class="header-anchor" href="#子问题三-safety-安全性" aria-label="Permalink to &quot;子问题三：Safety（安全性）&quot;">​</a></h3><p>Raft 的安全性由以下机制保证：</p><ol><li><p><strong>选举限制</strong>：Candidate 的日志必须至少和多数派节点一样新（lastLogTerm 更大，或 lastLogIndex 更大），否则无法当选。这保证了不会选出日志落后的 Leader。</p></li><li><p><strong>只追加不覆盖</strong>：Leader 永远不会覆盖或删除自己的日志条目，只通过 AppendEntries 强制 Follower 与自己一致。</p></li><li><p><strong>提交前序条目</strong>：Leader 只能提交<strong>当前任期</strong>的日志（通过提交当前任期的条目，隐式提交所有前序条目）。这避免了 Figure 8 问题——前任 Leader 的已复制但未提交的条目不被错误地认为是已提交的。</p></li></ol><h3 id="raft-在实际产品中的应用表" tabindex="-1">Raft 在实际产品中的应用表 <a class="header-anchor" href="#raft-在实际产品中的应用表" aria-label="Permalink to &quot;Raft 在实际产品中的应用表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>产品</th><th>使用方式</th><th>说明</th></tr></thead><tbody><tr><td><strong>etcd</strong></td><td>原生实现</td><td>Kubernetes 的配置存储，完全基于 Raft</td></tr><tr><td><strong>TiKV</strong></td><td>原生实现</td><td>TiDB 的底层 KV 存储，每个 Region 使用 Raft</td></tr><tr><td><strong>Consul</strong></td><td>原生实现（修改版）</td><td>服务发现与配置管理</td></tr><tr><td><strong>Nacos</strong></td><td>基于 JRaft (SOFAJRaft)</td><td>CP 模式下的配置中心</td></tr><tr><td><strong>RocketMQ</strong></td><td>基于 DLedger (Raft 变体)</td><td>DLedger 模式下的 CommitLog 复制</td></tr><tr><td><strong>CockroachDB</strong></td><td>原生实现</td><td>每个 Range 使用 Raft 的 MultiRaft</td></tr></tbody></table><h3 id="raft-vs-paxos-对比表" tabindex="-1">Raft vs Paxos 对比表 <a class="header-anchor" href="#raft-vs-paxos-对比表" aria-label="Permalink to &quot;Raft vs Paxos 对比表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>Paxos (Multi-Paxos)</th><th>Raft</th></tr></thead><tbody><tr><td><strong>可理解性</strong></td><td>较低，理论抽象层次高</td><td>较高，设计了明确的分解和约束</td></tr><tr><td><strong>Leader 选举</strong></td><td>无内置机制，需额外实现</td><td>内置 RequestVote RPC</td></tr><tr><td><strong>日志复制</strong></td><td>允许多个 Proposer 并发提案</td><td>只有 Leader 可以追加日志</td></tr><tr><td><strong>成员变更</strong></td><td>联合共识（Joint Consensus）</td><td>单节点变更（Single-Server Change）</td></tr><tr><td><strong>安全性</strong></td><td>证明完备但复杂</td><td>通过五项约束清晰保证</td></tr><tr><td><strong>实现难度</strong></td><td>较高，切面多、细节多</td><td>相对较低，边界清晰</td></tr><tr><td><strong>性能</strong></td><td>理论上支持乱序提交（更优）</td><td>强制顺序提交（实现简单）</td></tr><tr><td><strong>成熟度</strong></td><td>历史悠久，理论完备</td><td>论文详细，参考实现多</td></tr></tbody></table><hr><h2 id="zab-协议" tabindex="-1">ZAB 协议 <a class="header-anchor" href="#zab-协议" aria-label="Permalink to &quot;ZAB 协议&quot;">​</a></h2><p>ZAB（ZooKeeper Atomic Broadcast）是 ZooKeeper 内部使用的原子广播协议，与 Raft 类似但不完全相同。</p><h3 id="四个模式详解" tabindex="-1">四个模式详解 <a class="header-anchor" href="#四个模式详解" aria-label="Permalink to &quot;四个模式详解&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>   ┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>   │                     ZAB 协议状态机                      │</span></span>
<span class="line"><span>   │                                                        │</span></span>
<span class="line"><span>   │  ┌──────────┐    ┌──────────┐                          │</span></span>
<span class="line"><span>   │  │ 选举模式  │───►│ 发现模式  │   Leader 候选节点选出     │</span></span>
<span class="line"><span>   │  │ Election │    │Discovery │   最新 epoch              │</span></span>
<span class="line"><span>   │  └──────────┘    └──────────┘                          │</span></span>
<span class="line"><span>   │       ▲                │                               │</span></span>
<span class="line"><span>   │       │                ▼                               │</span></span>
<span class="line"><span>   │       │         ┌──────────┐                          │</span></span>
<span class="line"><span>   │       │         │ 同步模式  │   Follower 与 Leader      │</span></span>
<span class="line"><span>   │       │         │   Sync   │   同步历史事务              │</span></span>
<span class="line"><span>   │       │         └──────────┘                          │</span></span>
<span class="line"><span>   │       │                │                               │</span></span>
<span class="line"><span>   │       │                ▼                               │</span></span>
<span class="line"><span>   │       │         ┌──────────┐                          │</span></span>
<span class="line"><span>   │       │         │ 广播模式  │   正常服务，原子广播       │</span></span>
<span class="line"><span>   │       │         │Broadcast │                          │</span></span>
<span class="line"><span>   │       │         └──────────┘                          │</span></span>
<span class="line"><span>   │       │                │                               │</span></span>
<span class="line"><span>   │       │    Leader 崩溃 / 失去多数派                     │</span></span>
<span class="line"><span>   │       └────────────────┘                               │</span></span>
<span class="line"><span>   └──────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><table tabindex="0"><thead><tr><th>模式</th><th>说明</th></tr></thead><tbody><tr><td><strong>选举模式 (Election)</strong></td><td>节点之间通过投票选出一个 Leader。与 Raft 不同，ZAB 的选举不仅看 Term，还看事务 ID（zxid）。zxid 高的节点更可能当选，保证当选的 Leader 拥有最完整的事务日志。</td></tr><tr><td><strong>发现模式 (Discovery)</strong></td><td>新 Leader 确定当前 epoch（朝代编号），并收集所有 Follower 的最新已接受事务。这一步确保 Leader 知道所有 Committed 的事务。</td></tr><tr><td><strong>同步模式 (Sync)</strong></td><td>Leader 将自己有而 Follower 缺失的事务发送给 Follower。所有 Follower 与 Leader 的日志对齐后，集群才进入广播模式。这与 Raft 的&quot;Leader 不回溯提交旧任期条目&quot;不同——ZAB 允许 Leader 在同步阶段补全并提交前朝的未提交事务。</td></tr><tr><td><strong>广播模式 (Broadcast)</strong></td><td>正常工作状态。Leader 以两阶段提交风格推进事务（Propose → Ack → Commit），但这是流水线化的——不需要等前一个事务完成就能开始下一个。</td></tr></tbody></table><h3 id="zab-与-raft-的异同对比表" tabindex="-1">ZAB 与 Raft 的异同对比表 <a class="header-anchor" href="#zab-与-raft-的异同对比表" aria-label="Permalink to &quot;ZAB 与 Raft 的异同对比表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>ZAB</th><th>Raft</th></tr></thead><tbody><tr><td><strong>日志结构</strong></td><td>基于 FIFO 队列的事务日志</td><td>基于索引的有序日志</td></tr><tr><td><strong>Leader 选举依据</strong></td><td>zxid（事务 ID）最大者优先</td><td>Term 较新 + 日志较完整者优先</td></tr><tr><td><strong>旧任期日志处理</strong></td><td>Leader 在同步阶段可以提交前任 Leader 的未完成事务</td><td>Leader 只能提交当前任期的条目（间接提交前序）</td></tr><tr><td><strong>提交策略</strong></td><td>Follower 收到 Commit 消息后提交</td><td>Leader 通过 commitIndex 推进告知 Follower</td></tr><tr><td><strong>成员变更</strong></td><td>静态配置，需重启</td><td>动态单节点变更</td></tr><tr><td><strong>设计哲学</strong></td><td>面向主备模式的快速恢复</td><td>面向通用共识的简单性</td></tr><tr><td><strong>应用场景</strong></td><td>ZooKeeper</td><td>etcd、Consul、TiKV 等</td></tr></tbody></table><hr><h2 id="其他协议" tabindex="-1">其他协议 <a class="header-anchor" href="#其他协议" aria-label="Permalink to &quot;其他协议&quot;">​</a></h2><h3 id="_2pc-3pc-对比" tabindex="-1">2PC / 3PC 对比 <a class="header-anchor" href="#_2pc-3pc-对比" aria-label="Permalink to &quot;2PC / 3PC 对比&quot;">​</a></h3><p><strong>两阶段提交 (2PC, Two-Phase Commit)</strong> 和 <strong>三阶段提交 (3PC, Three-Phase Commit)</strong> 是实现分布式事务的经典协议。</p><p>2PC 流程：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Coordinator (协调者)                    Participants (参与者)</span></span>
<span class="line"><span>      │                                       │</span></span>
<span class="line"><span>      │ ──────── Prepare (询问) ──────────►   │  阶段一：投票</span></span>
<span class="line"><span>      │                                       │</span></span>
<span class="line"><span>      │ ◄─────── Vote (Yes/No) ──────────     │</span></span>
<span class="line"><span>      │                                       │</span></span>
<span class="line"><span>      │ ─── 收集所有投票，决定 Commit/Abort ──  │</span></span>
<span class="line"><span>      │                                       │</span></span>
<span class="line"><span>      │ ──────── Commit/Abort (执行) ─────►    │  阶段二：执行</span></span>
<span class="line"><span>      │                                       │</span></span>
<span class="line"><span>      │ ◄─────── Ack ────────────────────     │</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>3PC 在 2PC 的基础上增加了一个<strong>预提交 (PreCommit)</strong> 阶段，并引入超时机制，旨在避免协调者单点故障导致的阻塞。</p><table tabindex="0"><thead><tr><th>维度</th><th>2PC</th><th>3PC</th></tr></thead><tbody><tr><td><strong>阶段数</strong></td><td>2</td><td>3</td></tr><tr><td><strong>阻塞性质</strong></td><td>协调者故障时参与者阻塞</td><td>通过超时机制，参与者可自主决定</td></tr><tr><td><strong>一致性保证</strong></td><td>强一致</td><td>强一致</td></tr><tr><td><strong>性能</strong></td><td>较低（两轮 RTT）</td><td>更低（三轮 RTT）</td></tr><tr><td><strong>网络分区处理</strong></td><td>不能处理，会阻塞</td><td>部分缓解，但不能完全解决</td></tr><tr><td><strong>实际应用</strong></td><td>XA 事务、部分分布式数据库</td><td>较少使用（网络分区的根本问题未解决）</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">2PC 的核心缺陷</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>正常情况：                   协调者故障后：</span></span>
<span class="line"><span>┌─────┐  Prepare / Vote    ┌─────┐  ???????????</span></span>
<span class="line"><span>│  C  │ ◄──────────────►   │  X  │             ← 协调者宕机</span></span>
<span class="line"><span>└─────┘                    └─────┘</span></span>
<span class="line"><span>   │                           │</span></span>
<span class="line"><span>   │                           │ 参与者已投 Yes，但不</span></span>
<span class="line"><span>   │                           │ 知道最终是 Commit 还是 Abort</span></span>
<span class="line"><span>   ▼                           ▼</span></span>
<span class="line"><span>┌─────────┐               ┌─────────┐</span></span>
<span class="line"><span>│Participant│             │Participant│ ← 持有锁，永久阻塞！</span></span>
<span class="line"><span>└─────────┘               └─────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div></div><h3 id="gossip-协议" tabindex="-1">Gossip 协议 <a class="header-anchor" href="#gossip-协议" aria-label="Permalink to &quot;Gossip 协议&quot;">​</a></h3><p>Gossip（流言）协议是一种去中心化的信息传播协议，灵感来源于人类社会中流言的传播方式。</p><p><strong>工作机制</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每个节点定期随机选择几个其他节点，交换自己所知的信息。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Round 1:    ●                   ← 1 个节点知道新信息</span></span>
<span class="line"><span>Round 2:    ● ● ●               ← 感染 3 个节点</span></span>
<span class="line"><span>Round 3:    ● ● ● ● ● ● ●       ← 感染 7 个节点</span></span>
<span class="line"><span>Round 4:    ● ● ● ● ● ● ● ● ● ● ● ← 感染几乎所有节点</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>Round O(log N): 全集群收敛</span></span>
<span class="line"><span></span></span>
<span class="line"><span>收敛时间：O(log N)，其中 N 为集群大小</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p><strong>三种传播模式</strong>：</p><table tabindex="0"><thead><tr><th>模式</th><th>机制</th><th>特点</th></tr></thead><tbody><tr><td><strong>Push</strong></td><td>节点主动将自身状态推送给对端</td><td>适合新信息快速扩散</td></tr><tr><td><strong>Pull</strong></td><td>节点主动从对端拉取状态更新</td><td>适合修复过期数据</td></tr><tr><td><strong>Push-Pull</strong></td><td>双向交换全量状态信息</td><td>收敛最快，Cassandra 使用此模式</td></tr></tbody></table><p><strong>实际应用场景</strong>：</p><table tabindex="0"><thead><tr><th>系统</th><th>用途</th></tr></thead><tbody><tr><td><strong>Cassandra</strong></td><td>集群成员发现、数据副本修复</td></tr><tr><td><strong>Consul</strong></td><td>Serf 组件使用 Gossip 做成员管理和故障检测</td></tr><tr><td><strong>Dynamo (AWS)</strong></td><td>成员管理与故障检测</td></tr><tr><td><strong>Redis Cluster</strong></td><td>节点间通过 Gossip 协议交换集群拓扑信息（PING/PONG 消息）</td></tr><tr><td><strong>Bitcoin / Ethereum</strong></td><td>P2P 网络中传播交易和区块</td></tr></tbody></table><hr><h2 id="经典高频面试题" tabindex="-1">经典高频面试题 <a class="header-anchor" href="#经典高频面试题" aria-label="Permalink to &quot;经典高频面试题&quot;">​</a></h2><h3 id="q3-raft-协议如何保证安全性-请详细说明三点安全保证。" tabindex="-1">Q3: Raft 协议如何保证安全性？请详细说明三点安全保证。 <a class="header-anchor" href="#q3-raft-协议如何保证安全性-请详细说明三点安全保证。" aria-label="Permalink to &quot;Q3: Raft 协议如何保证安全性？请详细说明三点安全保证。&quot;">​</a></h3><p><strong>答案：</strong></p><p>Raft 协议的安全性（Safety）保证了以下核心属性：<strong>一旦某条日志条目被提交（committed），那么未来任何时候，所有后续的 Leader 都必须拥有这条日志条目。</strong> 换句话说，已提交的条目永远不会丢失。</p><p>Raft 通过三条核心规则来保证这一点：</p><p><strong>安全保证一：Leader 日志完整性约束（Election Restriction）</strong></p><p>这是 Raft 最重要的安全保证。在选举阶段，Candidate 发送 RequestVote RPC 时会携带自己的日志信息（<code>lastLogIndex</code> 和 <code>lastLogTerm</code>）。Follower 收到投票请求后，会比较 Candidate 和自己的日志谁更&quot;新&quot;：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Follower 投票判断逻辑（伪代码）：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>def shouldVote(candidate):</span></span>
<span class="line"><span>    if candidate.lastLogTerm &gt; self.lastLogTerm:</span></span>
<span class="line"><span>        return YES   # 任期更大 → 更新 → 投票</span></span>
<span class="line"><span>    elif candidate.lastLogTerm == self.lastLogTerm and \\</span></span>
<span class="line"><span>         candidate.lastLogIndex &gt;= self.lastLogIndex:</span></span>
<span class="line"><span>        return YES   # 任期相同，索引更大或相等 → 投票</span></span>
<span class="line"><span>    else:</span></span>
<span class="line"><span>        return NO    # 日志不如我 → 拒绝</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>这个约束确保了：</p><ul><li>任何当选的 Leader <strong>一定包含了所有已提交的日志条目</strong>；</li><li>因为一条日志要被提交就必须复制到多数派节点，而 Candidate 要当选也必须获得多数派投票，这两个多数派必然有交集；</li><li>交集处的节点同时&quot;提交了日志&quot;和&quot;投票给了 Candidate&quot;，且 Candidate 的日志不比该节点旧，所以 Candidate 一定包含该已提交日志。</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>多数派交集证明示意图：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  提交日志的多数派:  [S1]  [S2]  [S3  ]</span></span>
<span class="line"><span>  投票的多数派:      [S2]  [S3  ]  [S4]  [S5]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  交集 = {S2, S3}</span></span>
<span class="line"><span>  → S2 和 S3 既提交了日志又投票给 Candidate</span></span>
<span class="line"><span>  → Candidate 的日志 &gt;= S2/S3 → Candidate 包含已提交日志</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><strong>安全保证二：Leader 只追加、不覆盖（Leader Append-Only）</strong></p><p>Leader 永远不会删除或覆盖自己的日志条目。当 Leader 通过 AppendEntries RPC 向 Follower 同步日志时：</p><ul><li>Leader 携带 <code>prevLogIndex</code> 和 <code>prevLogTerm</code> 告诉 Follower：&quot;假设我这之前的日志和你一致&quot;；</li><li>Follower 检查该位置是否匹配：匹配则接受新条目，不匹配则拒绝；</li><li>Leader 被拒绝后，会将 <code>nextIndex</code> 减 1，继续尝试，直到找到第一个匹配的位置；</li><li>找到匹配点之后，Leader 会用<strong>自己的日志覆盖</strong> Follower 在匹配点之后的不一致日志。</li></ul><p>关键约束：<strong>Leader 只强制 Follower 与自己的日志一致，但 Leader 自己的已提交日志绝不被覆盖。</strong></p><p><strong>安全保证三：只提交当前任期的日志（Commitment Rule from Current Term）</strong></p><p>这是 Raft 论文中处理 Figure 8 问题的关键规则。Leader 只在当前任期的日志被多数派复制时，才推进 commitIndex。推进当前任期的 commitIndex 会<strong>顺带提交所有前序未提交的日志</strong>——但这些前序日志不会被单独提交，而是通过&quot;当前任期提交&quot;来间接保证。</p><p>这种方式确保了：即使发生了 Figure 8 的场景，前任的日志也不会被错误地当作&quot;已提交&quot;然后被覆盖。</p><p><strong>安全保证汇总</strong>：</p><table tabindex="0"><thead><tr><th>规则</th><th>防护目标</th><th>机制</th></tr></thead><tbody><tr><td>Election Restriction</td><td>防止丢失已提交日志的节点成为 Leader</td><td>Candidate 日志必须至少和多数派一样新</td></tr><tr><td>Leader Append-Only</td><td>防止 Leader 侧的日志被破坏</td><td>Leader 永远不修改已有条目</td></tr><tr><td>Commit Current Term</td><td>防止前任未提交日志被错误提交后又被覆盖</td><td>只通过提交当前任期条目间接提交前序</td></tr></tbody></table><hr><h3 id="q4-请对比-paxos-和-raft-的异同。" tabindex="-1">Q4: 请对比 Paxos 和 Raft 的异同。 <a class="header-anchor" href="#q4-请对比-paxos-和-raft-的异同。" aria-label="Permalink to &quot;Q4: 请对比 Paxos 和 Raft 的异同。&quot;">​</a></h3><p><strong>答案：</strong></p><p><strong>相同点（底层原理一致）</strong>：</p><ol><li><strong>都是多数派协议</strong>：任何决策都需要获得多数派（Majority / Quorum）节点的响应，容忍少数节点故障（<code>2F + 1</code> 个节点容忍 <code>F</code> 个故障）；</li><li><strong>都基于 Leader 机制</strong>：Multi-Paxos 和 Raft 在实际工程中都选举一个稳定的 Leader 来推进日志；</li><li><strong>日志结构一致</strong>：都是有序的日志条目序列，通过复制日志实现状态机复制；</li><li><strong>安全性保证一致</strong>：都保证已提交的日志不会被覆盖，Leader 都拥有最完整的日志；</li><li><strong>成员变更都需要特殊处理</strong>：都面临从旧配置过渡到新配置时的安全性问题。</li></ol><p><strong>不同点（设计哲学和实现路径差异）</strong>：</p><table tabindex="0"><thead><tr><th>对比维度</th><th>Paxos (Multi-Paxos)</th><th>Raft</th></tr></thead><tbody><tr><td><strong>理论完整性</strong></td><td>Lamport 给出了严格的 TLA+ 形式化证明，但论文主要描述 Basic Paxos，Multi-Paxos 细节留白较多</td><td>Ongaro 的博士论文详尽描述了所有细节，包含 66 页的 TLA+ 规约，便于工程实现</td></tr><tr><td><strong>问题分解</strong></td><td>没有清晰的问题分解，所有机制交织在一起</td><td>明确分解为 Leader Election、Log Replication、Safety 三个独立子问题</td></tr><tr><td><strong>Leader 选举</strong></td><td>无内置机制，Multi-Paxos 的 Leader 选举需要额外协议或外部协调</td><td>内置 RequestVote RPC，有超时、随机退避、Term 递增等完整机制</td></tr><tr><td><strong>日志提交方向</strong></td><td>日志可以向&quot;后&quot;提交（允许乱序完成），理论上并发度更高</td><td>严格按索引顺序提交，简单但可能限制部分并发</td></tr><tr><td><strong>日志不一致修复</strong></td><td>Leader 将 Follower 的日志逐一覆盖为自己的日志（单向修复）</td><td>Leader 回溯找到匹配点后，从匹配点开始覆盖（双向修复）</td></tr><tr><td><strong>成员变更</strong></td><td>联合共识（Joint Consensus）：过渡期同时允许新旧两套配置</td><td>单节点变更（Single-Server Change）：每次只增删一个节点</td></tr><tr><td><strong>快照机制</strong></td><td>无内置定义</td><td>明确定义了 InstallSnapshot RPC 来传输快照</td></tr><tr><td><strong>实现生态</strong></td><td>Google Chubby、Tencent PhxPaxos、Alibaba X-Paxos（各自实现差异大）</td><td>etcd、Consul、TiKV、CockroachDB（参考实现标准统一）</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">通俗类比</p><p>如果把共识算法比作法律体系：</p><ul><li><strong>Paxos</strong> 像<strong>判例法</strong>：规则分散在多个判例（论文）中，核心原则明确（两阶段 + 多数派），但边界情况和实施细则需要各家自行解释和实现。</li><li><strong>Raft</strong> 像<strong>成文法</strong>：所有规则都被明确写在&quot;法条&quot;（论文 + TLA+）中，每个操作的输入输出都有精确约定，谁实现都应该一致。</li></ul></div><p><strong>选型建议</strong>：</p><ul><li>如果需要<strong>理论深度和极致性能</strong>（如数据库存储层），Paxos 的灵活性更有优势；</li><li>如果需要<strong>工程确定性和可维护性</strong>（如配置中心、服务发现），Raft 的简洁性更合适；</li><li>当前行业趋势是 Raft 在<strong>应用层基础设施</strong>中占据主流，而 Paxos 在<strong>存储层</strong>仍有广泛使用。</li></ul><hr><h3 id="q5-什么是脑裂-split-brain-如何避免" tabindex="-1">Q5: 什么是脑裂（Split-Brain）？如何避免？ <a class="header-anchor" href="#q5-什么是脑裂-split-brain-如何避免" aria-label="Permalink to &quot;Q5: 什么是脑裂（Split-Brain）？如何避免？&quot;">​</a></h3><p><strong>答案：</strong></p><p><strong>定义</strong>：</p><p>脑裂（Split-Brain）是指在一个集群中，由于网络分区（Network Partition）导致集群分裂为两个或多个互不通信的子集群，每个子集群都认为自己才是&quot;合法&quot;的集群，并分别选举出自己的 Master / Leader，开始独立接受外部请求，最终导致数据出现<strong>不可合并的分叉（fork）</strong>。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>脑裂分叉示意：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>         正常状态                        脑裂状态</span></span>
<span class="line"><span>   ┌─────────────────┐           ┌──────────────┐    ┌──────────────┐</span></span>
<span class="line"><span>   │  Master (A)      │           │ Master (A)    │    │ Master (C)   │</span></span>
<span class="line"><span>   │                  │           │               │    │              │</span></span>
<span class="line"><span>   │  ┌──┐ ┌──┐ ┌──┐ │           │ 写入: x=100   │    │ 写入: x=200  │</span></span>
<span class="line"><span>   │  │S1│ │S2│ │S3│ │           │               │    │              │</span></span>
<span class="line"><span>   │  └──┘ └──┘ └──┘ │           │  ┌──┐ ┌──┐    │    │  ┌──┐        │</span></span>
<span class="line"><span>   └─────────────────┘           │  │S1│ │S2│    │    │  │S3│        │</span></span>
<span class="line"><span>                                 │  └──┘ └──┘    │    │  └──┘        │</span></span>
<span class="line"><span>                                 └──────────────┘    └──────────────┘</span></span>
<span class="line"><span>                                          │                   │</span></span>
<span class="line"><span>                                       分叉 A             分叉 B</span></span>
<span class="line"><span>                                   x=100 (两个 Master)  x=200</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   网络恢复后：两个 Master 都认为自己是对的 → 数据不可合并 → 灾难</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p><strong>避免脑裂的核心策略</strong>：</p><p><strong>策略一：法定人数（Quorum）</strong></p><p>这是最基础也是最核心的策略。规定任何选举 / 决策都必须在获得<strong>超过半数节点</strong>的同意后才能生效。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>节点总数 N = 5, 法定人数 = ⌊N/2⌋ + 1 = 3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────┐       ┌──────────┐</span></span>
<span class="line"><span>│ 分区 A: 3 个节点  │       │ 分区 B: 2 个节点 │</span></span>
<span class="line"><span>│ 可以选出 Leader   │       │ 无法达到法定人数   │</span></span>
<span class="line"><span>│ 可以接受写入      │       │ 拒绝所有写入      │</span></span>
<span class="line"><span>└──────────────────┘       └──────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ 全集群只有一个分区能正常服务</span></span>
<span class="line"><span>→ 脑裂被阻止（B 分区无法选出 Leader）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>这就是为什么 Raft、ZAB 都要求 <strong><code>2F + 1</code> 个节点</strong>才能容忍 <code>F</code> 个故障。如果部署了偶数个节点（如 4 个节点），任意分区成 2+2 都会导致<strong>两边都无法达到法定人数</strong>，整个集群不可用。</p><p><strong>策略二：Fencing Token（栅栏令牌）</strong></p><p>法定人数保证了分区后不会出现两个 Leader 同时选举成功。但还存在一个边界场景：旧 Leader 暂时网络隔离但尚未感知到自己已失联，此时它可能仍然认为自己是 Leader 并尝试写入。</p><p>Fencing Token 机制在共享存储中维护一个<strong>单调递增的 Token 号</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>流程：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 新 Leader 当选时，向协调服务获取一个新的 Token（如 token=6）</span></span>
<span class="line"><span>2. 旧 Leader 持有的 Token 已过期（如 token=5）</span></span>
<span class="line"><span>3. 每次写入共享存储时，必须携带自己的 Token</span></span>
<span class="line"><span>4. 共享存储只接受携带最大 Token（或更大）的写入请求</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────────────────────────┐</span></span>
<span class="line"><span>│      ZooKeeper / etcd                │</span></span>
<span class="line"><span>│      current_fencing_token = 6       │</span></span>
<span class="line"><span>└──────────┬───────────────────────────┘</span></span>
<span class="line"><span>           │</span></span>
<span class="line"><span>      ┌────┴────┐</span></span>
<span class="line"><span>      │         │</span></span>
<span class="line"><span>      ▼         ▼</span></span>
<span class="line"><span> ┌─────────┐  ┌─────────┐</span></span>
<span class="line"><span> │ Old M   │  │ New M   │</span></span>
<span class="line"><span> │token=5  │  │token=6  │</span></span>
<span class="line"><span> └────┬────┘  └────┬────┘</span></span>
<span class="line"><span>      │            │</span></span>
<span class="line"><span>      ▼            ▼</span></span>
<span class="line"><span> ┌──────────────────────────────────────┐</span></span>
<span class="line"><span> │          共享存储                      │</span></span>
<span class="line"><span> │ max_seen_token = 6                   │</span></span>
<span class="line"><span> │                                      │</span></span>
<span class="line"><span> │ Old M 写入 (token=5) → REJECTED!     │</span></span>
<span class="line"><span> │ New M 写入 (token=6) → ACCEPTED      │</span></span>
<span class="line"><span> └──────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br></div></div><p><strong>策略三：Raft PreVote（预投票）</strong></p><p>PreVote 主要防止<strong>网络分区恢复后的&quot;捣乱式选举&quot;</strong>，虽然不是直接防止脑裂，但能大幅降低不必要的 Leader 切换，减少脑裂发生的窗口期。</p><p>核心思想：节点发现心跳超时后，不立即增加 Term 并发起正式选举，而是先发起一轮 PreVote（预投票），询问其他节点&quot;如果我现在发起选举，你们会投票给我吗？&quot;</p><ul><li>如果节点处于网络隔离状态，它无法联络到多数派节点 → PreVote 失败 → 不会增加 Term → 不会造成集群震荡；</li><li>网络恢复后，该节点恢复正常心跳接收，不会因为自己的 Term 过高而破坏正常运行的集群。</li></ul><p><strong>策略四：Redis Sentinel 的主观下线 + 客观下线</strong></p><p>Redis Sentinel 采用了一种更细粒度的两阶段决策机制来避免脑裂，通过多个 Sentinel 节点的投票确认，确保只有真正失联的 Master 才会被切换。</p>`,120)])])}const m=n(t,[["render",l]]);export{u as __pageData,m as default};
